const msg = $input.first().json;
const text = (msg.body || msg.message || msg.text || "").toLowerCase();

let intent = "fallback";
if (/ola|oi|bom dia|boa tarde|boa noite|inicio|start/i.test(text)) intent = "greeting";
else if (/cardapio|catalogo|produtos|servicos|lista|tem|vende/i.test(text)) intent = "catalog";
else if (/preco|valor|custa|quanto|orcamento/i.test(text)) intent = "pricing";
else if (/comprar|quero|pedido|pagar|fechar/i.test(text)) intent = "purchase";
else if (/humano|atendente|pessoa|falar|ajuda/i.test(text)) intent = "human";

return { intent, text, from: msg.from || msg.sender, original: msg };
